-- 2. Thanet × SEO
INSERT INTO public.local_content (service_slug, town_slug, intro_paragraph, local_context, competition_landscape, success_approach, local_stats, pain_points, solutions, faqs, layout_variant)
VALUES (
  'seo',
  'thanet',
  'Thanet''s three coastal towns generate search patterns unlike anywhere else in Kent. Tourism keywords spike dramatically from April through September, then fall away. But the resident population of 142,000 searches year-round for local services, trades, and professional help. The businesses that thrive in Thanet are those that capture both audiences: the summer visitor searching for Margate restaurants near the Turner Contemporary, and the Ramsgate resident searching for a plumber in January. Most Thanet businesses have no SEO strategy at all. They rely on summer footfall and word of mouth, then struggle through the winter months when their website generates no traffic. Our SEO campaigns are built from the ground up for Thanet''s dual-season reality, targeting tourism keywords that capture summer revenue and resident keywords that sustain the business year-round.',
  'Thanet''s search landscape splits into three distinct town profiles. Margate generates the highest volume of tourism-related searches, driven by the Turner Contemporary, Dreamland, the Shell Grotto, and the Creative Quarter. Ramsgate''s Royal Harbour and Harbour Parade dining scene create food, drink, and maritime search intent. Broadstairs'' Viking Bay, Dickens connections, and Folk Week generate family-oriented tourism searches with strong seasonal peaks. Thanet Parkway station has created new commuter-related searches. Westwood Cross generates retail comparison searches. Across all three towns, resident service searches form the year-round baseline.',
  'SEO competition in Thanet has intensified as the district''s profile has grown. TripAdvisor, Airbnb, and national tourism platforms dominate many Margate and Broadstairs accommodation keywords. Established hospitality businesses with years of review accumulation have strong Google Map Pack positions. However, most Thanet trades, professional services, and non-hospitality businesses have no SEO strategy, meaning targeted campaigns in these sectors can achieve rapid results.',
  'We approach Thanet SEO as a dual-season discipline. Summer campaigns target tourism keywords for each of the three towns with content that captures advance booking searches months before visitors arrive. Year-round campaigns target the resident population of 142,000 with service-specific keywords. Google Business Profile optimisation covers all three towns separately. Content creation follows the seasonal pattern: tourism-focused content building from January through the summer peak, then pivoting to resident-focused content through autumn and winter.',
  '{"population": 142000, "growth": "Tourism-driven regeneration with growing creative economy", "business_districts": ["Margate Old Town", "Turner Contemporary area", "Ramsgate Royal Harbour", "Broadstairs High Street", "Westwood Cross"], "key_fact": "Dramatic seasonal search volume swing requiring dual-season SEO strategy"}',
  '[{"title": "Invisible during Thanet''s crucial summer search season", "description": "Tourism searches for Margate, Ramsgate, and Broadstairs spike enormously from April through September. Businesses without SEO are invisible during the months that generate the majority of their annual revenue. Competitors who rank on page one absorb the tourist traffic while others rely on passing footfall alone."}, {"title": "Zero search visibility during Thanet''s winter months", "description": "When the tourists leave, Thanet businesses that relied on summer footfall have nothing. Their websites generate no search traffic because they have no content targeting the resident population of 142,000. The winter months drain cash reserves that a steady flow of SEO-driven resident enquiries could sustain."}, {"title": "Tourism platforms outranking genuine Thanet businesses", "description": "TripAdvisor, Airbnb, Booking.com, and national tourism sites aggressively target Thanet keywords. They push genuine local businesses down the results, capturing visitors and taking commissions from bookings that should come directly. Without a strategy to outrank these platforms, your Thanet business pays intermediaries for its own customers."}]',
  '[{"title": "Dual-season SEO strategy for Thanet businesses", "description": "We build campaigns that target tourism keywords from spring through summer and resident service keywords year-round. Your Thanet business ranks for visitors searching Margate restaurants or Broadstairs accommodation during peak season, and for locals searching for trades and professional services during the quieter months."}, {"title": "Three-town Google presence covering Margate, Ramsgate, and Broadstairs", "description": "We optimise your Google Business Profile and build town-specific landing pages for each of Thanet''s three main towns. A restaurant in Ramsgate ranks for Royal Harbour dining searches. An electrician ranks in Margate, Ramsgate, and Broadstairs separately. Each town gets genuinely unique content reflecting its distinct character."}, {"title": "Advance-booking content capturing tourist searches months early", "description": "Tourists start searching for Thanet accommodation and activities months before their visit. We create and optimise seasonal content that ranks before the peak arrives, capturing bookings in January for summer visits. By the time competitors notice the season has started, your pages are already established in the results."}]',
  '[{"question": "How long before I see SEO results for Thanet searches?", "answer": "Town-specific and long-tail terms typically show movement within six to ten weeks. Competitive tourism keywords for Margate and Broadstairs may take four to six months. We recommend starting SEO well before peak season to ensure your Thanet business ranks when summer traffic arrives."}, {"question": "Can you help me rank for tourism searches in Margate?", "answer": "Yes. Margate tourism SEO is one of our specialities. We build content targeting Turner Contemporary visitors, Dreamland weekenders, Creative Quarter browsers, and Shell Grotto tourists. Each attraction generates distinct search patterns that we target with specific content and optimisation."}, {"question": "How do I maintain search visibility during Thanet''s winter?", "answer": "Our dual-season approach ensures your website targets the resident population of 142,000 with service-specific content year-round. Winter content focuses on local needs rather than tourism, maintaining enquiry flow during the months that tourism-dependent businesses typically struggle."}, {"question": "Should I target Thanet as a whole or each town separately?", "answer": "For most businesses, targeting each town separately delivers better results. Margate, Ramsgate, and Broadstairs have distinct search profiles and competition levels. We build town-specific pages with genuinely unique content for each, which Google rewards with higher rankings than a single generic Thanet page."}]',
  'authority'
)
