-- 6. Thanet × Social Media Setup
INSERT INTO public.local_content (service_slug, town_slug, intro_paragraph, local_context, competition_landscape, success_approach, local_stats, pain_points, solutions, faqs, layout_variant)
VALUES (
  'social-media-setup',
  'thanet',
  'Social media is the engine that drives Thanet''s tourism economy. A single Instagram post of a sunset over Margate''s harbour can generate thousands of impressions and drive weekend visitors. A Ramsgate restaurant tagged in a food blogger''s story fills tables for weeks. A Broadstairs B&B with strong TripAdvisor and Google reviews books out months in advance. Thanet is one of the most Instagrammable districts in Kent, and the businesses that understand this are thriving. But the majority of Thanet businesses have either no social media presence or dormant profiles that fail to capture any of this organic attention. The Turner Contemporary and Dreamland drive tens of thousands of visitors to Thanet annually. If your business is not visible on the platforms these visitors use to plan and share their trips, you are invisible to the market that funds Thanet''s economy.',
  'Thanet''s social media landscape is driven by visual platforms and tourism. Instagram is the dominant platform for Margate''s creative and hospitality scene, with the Turner Contemporary, Dreamland, and the Shell Grotto generating enormous amounts of user-created content. Facebook community groups for Margate, Ramsgate, and Broadstairs residents are active recommendation engines. TripAdvisor and Google reviews heavily influence tourist accommodation and dining decisions. The DFL creative community maintains active personal social media presences that amplify local businesses they frequent. Broadstairs'' Folk Week and Margate''s various art events create annual social media spikes.',
  'Social media quality in Thanet mirrors the branding bifurcation. Creative Quarter businesses and DFL-run hospitality venues maintain polished, active Instagram accounts with professional photography. Established local businesses typically have minimal or dormant presence. The gap is particularly visible in hospitality, where Instagram is effectively a prerequisite for tourist discovery. Trades and professional services have almost no social media presence, missing the resident recommendation activity that happens in local Facebook groups.',
  'We set up social media for Thanet businesses based on the platform mix that matches their audience. Tourism-facing businesses get Instagram-first strategies built for the visual discovery that drives Thanet visits. Restaurants and bars get platforms optimised for food photography and review management. Trades and services get Facebook profiles optimised for community group recommendations. Every profile is branded consistently and optimised to capture the specific social media activity that drives revenue in each Thanet town.',
  '{"population": 142000, "growth": "Highly visual tourism economy driven by social media discovery", "business_districts": ["Margate Creative Quarter", "Ramsgate Harbour Parade", "Broadstairs seafront", "Westwood Cross"], "key_fact": "Instagram is a primary discovery platform for Thanet tourism businesses"}',
  '[{"title": "Invisible on Instagram in one of Kent''s most photogenic districts", "description": "Thanet generates enormous Instagram content through the Turner Contemporary, Dreamland, Margate''s sunsets, Viking Bay, and the Royal Harbour. Tourists browse these images and look for businesses to visit. A Thanet business without an active, branded Instagram profile is invisible to the social media discovery process that drives a significant share of tourist spending."}, {"title": "Missing from Thanet community group recommendations", "description": "Facebook groups for Margate, Ramsgate, and Broadstairs residents generate daily recommendation requests for everything from electricians to restaurants. Without an active Facebook business page, you cannot be tagged in these conversations, cannot respond to requests, and miss the word-of-mouth referral activity that sustains businesses year-round."}, {"title": "No review management strategy for Thanet tourism businesses", "description": "TripAdvisor and Google reviews make or break Thanet hospitality businesses. A run of negative reviews on TripAdvisor during peak season can devastate a Broadstairs B&B or a Ramsgate restaurant. Without active review management, monitoring, and response, your online reputation is entirely in the hands of whoever chooses to leave feedback."}]',
  '[{"title": "Instagram-first setup for Thanet tourism businesses", "description": "We build and optimise your Instagram business profile for visual discovery in Thanet''s tourism market. Professional bio, consistent visual grid strategy, hashtag research for Margate, Ramsgate, and Broadstairs tourism tags, and content templates that maintain quality without requiring a professional photographer for every post."}, {"title": "Review platform optimisation for Thanet hospitality", "description": "We set up and optimise your TripAdvisor, Google Business Profile, and other review platforms with professional imagery, accurate information, and response templates. A structured review generation strategy makes it easy for satisfied customers to leave feedback, building the social proof that drives bookings throughout the season."}, {"title": "Community-group-ready Facebook for Thanet trades and services", "description": "We build Facebook business profiles optimised for engagement in Margate, Ramsgate, and Broadstairs community groups. Professional branding, portfolio imagery, complete service information, and content templates ensure your profile converts recommendation requests into enquiries from Thanet''s 142,000 permanent residents."}]',
  '[{"question": "Which social media platforms should my Thanet business be on?", "answer": "For tourism-facing businesses, Instagram is essential. For hospitality, TripAdvisor and Google reviews are critical. For trades and services targeting residents, Facebook is the priority for community group engagement. We recommend the right platform mix based on your specific Thanet audience and business type."}, {"question": "How important is Instagram for Thanet businesses?", "answer": "For tourism-facing businesses, extremely important. Thanet is one of the most Instagrammable areas in Kent, and visitors use Instagram to discover and choose businesses during their trip. A strong Instagram presence with consistent posting can drive significant footfall, particularly in Margate and the harbour areas."}, {"question": "Do you manage social media ongoing or just set it up?", "answer": "This service focuses on professional setup: creating, branding, and optimising your profiles so they are ready to generate business across Thanet. We also provide content templates, hashtag strategies, and posting guides for each season. Ongoing management is available as a separate service."}, {"question": "How do I get more reviews for my Thanet business?", "answer": "We implement a structured review generation strategy as part of your social media setup. This includes optimised review platform profiles, QR codes and prompt cards for physical locations, and automated post-visit email or SMS requests. The system makes it easy for satisfied customers to leave feedback on the platforms that matter most in Thanet."}]',
  'trust'
)
ON CONFLICT (service_slug, town_slug) DO UPDATE SET
  intro_paragraph = EXCLUDED.intro_paragraph,
  local_context = EXCLUDED.local_context,
  competition_landscape = EXCLUDED.competition_landscape,
