-- 7. Thanet × Digital Marketing
INSERT INTO public.local_content (service_slug, town_slug, intro_paragraph, local_context, competition_landscape, success_approach, local_stats, pain_points, solutions, faqs, layout_variant)
VALUES (
  'digital-marketing',
  'thanet',
  'Thanet''s tourism economy runs on a seasonal clock that rewards businesses who market early and penalises those who start late. By the time a Margate seafront business decides to advertise in June, the visitors are already arriving and the advertising costs have spiked. The businesses that capture the most summer revenue are those running digital marketing campaigns from January onwards, building visibility in search results and social media feeds well before the first warm weekend. But digital marketing in Thanet is not just about tourists. The district''s 142,000 permanent residents need tradespeople, dentists, accountants, and every other service year-round. The businesses that thrive in Thanet use digital marketing to capture both audiences: summer visitors through targeted campaigns and year-round residents through consistent local presence. Most Thanet businesses do neither effectively.',
  'Thanet''s digital marketing landscape splits between seasonal tourism campaigns and year-round resident targeting. Margate draws the heaviest tourism advertising spend, with businesses competing for visibility around the Turner Contemporary, Dreamland, and the Creative Quarter. Ramsgate''s Royal Harbour dining scene generates food and drink advertising activity. Broadstairs'' family tourism creates demand for family-friendly activity and accommodation advertising. Thanet Parkway station has opened the district to day-trip visitors who can be targeted through commuter-area campaigns. Westwood Cross provides the main retail advertising battleground.',
  'Digital advertising competition in Thanet intensifies dramatically during peak season. Google Ads costs for tourism keywords spike from May onwards. Facebook and Instagram advertising costs rise as hospitality businesses flood the platforms. Outside peak season, advertising costs drop significantly but most Thanet businesses also stop advertising, creating an opportunity for those who maintain year-round campaigns to capture resident demand at lower cost.',
  'We build Thanet digital marketing campaigns around the seasonal calendar. Pre-season campaigns from January onwards target advance bookers and trip planners searching for Margate, Ramsgate, and Broadstairs. Peak season campaigns maximise visibility when competition is highest, using precise targeting to avoid wasting budget. Post-season campaigns pivot to targeting the permanent resident population, maintaining enquiry flow through autumn and winter. Every campaign is measured against actual bookings or leads, not vanity metrics.',
  '{"population": 142000, "growth": "Tourism-driven economy requiring seasonal campaign management", "business_districts": ["Margate seafront", "Ramsgate Royal Harbour", "Broadstairs", "Westwood Cross", "Margate Creative Quarter"], "key_fact": "Pre-season digital marketing from January determines who wins the summer tourism spend"}',
  '[{"title": "Starting summer advertising too late in Thanet", "description": "Thanet businesses that begin advertising in June are already behind. Tourists start researching and booking Margate, Ramsgate, and Broadstairs trips months in advance. By peak season, advertising costs have spiked and the best customers have already booked. Late starters pay more for worse results while early advertisers have already filled their summer calendars."}, {"title": "Stopping advertising in winter and losing Thanet residents", "description": "When summer ends, most Thanet businesses switch off their digital marketing. But 142,000 people still live in the district and still need services. The businesses that maintain year-round advertising capture this resident demand at significantly lower cost, sustaining revenue through the months that holiday-dependent businesses find hardest."}, {"title": "Wasting budget on untargeted campaigns across Thanet", "description": "A Margate restaurant advertising to the whole of Kent wastes budget on people who will never visit. A Broadstairs B&B targeting all of England dilutes its advertising across millions of people who are not planning a trip to Thanet. Without precise geographic and interest-based targeting, Thanet advertising budgets evaporate with minimal return."}]',
  '[{"title": "Pre-season campaigns that fill Thanet businesses before summer", "description": "We launch advertising campaigns from January targeting trip planners and advance bookers searching for Margate, Ramsgate, and Broadstairs. By the time peak season arrives, your business has a healthy booking pipeline built at lower pre-season advertising costs. Your competitors scrambling to advertise in June are already too late."}, {"title": "Year-round resident campaigns for sustainable Thanet revenue", "description": "We maintain digital advertising targeting Thanet''s 142,000 permanent residents throughout the year. Google and social media campaigns reach Ramsgate homeowners, Broadstairs families, and Margate residents with service-specific messaging. Winter advertising costs are significantly lower, delivering strong returns that sustain your business through the off-season."}, {"title": "Full-funnel tracking from Thanet ad click to booking or lead", "description": "Every campaign includes complete conversion tracking. You know exactly which keywords, ads, and platforms generate bookings, phone calls, and enquiries from Thanet customers. Monthly reporting shows cost per booking or lead, broken down by season, platform, and town, so you can invest intelligently in what actually works."}]',
  '[{"question": "What digital marketing budget does a Thanet business need?", "answer": "Thanet tourism businesses typically need five hundred to fifteen hundred pounds per month during peak season and three hundred to seven hundred in the off-season. Year-round service businesses see results from five hundred to one thousand monthly. We provide forecasts based on actual Thanet keyword costs before you commit."}, {"question": "When should I start advertising for summer in Thanet?", "answer": "January or February at the latest. Trip planners start searching for Margate, Ramsgate, and Broadstairs months before they visit. Pre-season campaigns build visibility and bookings at lower costs before the advertising market becomes crowded. Starting in June means paying premium prices for diminished returns."}, {"question": "Should I advertise differently for tourists and residents?", "answer": "Absolutely. Tourist campaigns target geographic areas outside Thanet, focus on visitor-oriented keywords, and run seasonally. Resident campaigns target postcodes within the district, focus on local service keywords, and run year-round. We build separate campaign structures for each audience with appropriate messaging and budgets."}, {"question": "Can you target people planning trips to specific Thanet towns?", "answer": "Yes. We can target people searching for Margate, Ramsgate, or Broadstairs specifically, as well as people who have shown interest in specific attractions like the Turner Contemporary, Dreamland, or Viking Bay. This precision ensures your advertising reaches people actively planning to visit your area."}]',
  'lead-gen'
)
ON CONFLICT (service_slug, town_slug) DO UPDATE SET
  intro_paragraph = EXCLUDED.intro_paragraph,
  local_context = EXCLUDED.local_context,
  competition_landscape = EXCLUDED.competition_landscape,
